   321→  const def = EXEC_WHITELIST[script];
   322→  if (!def) { res.status(400).json({ error: "Comando no permitido" }); return; }
   323→
   324→  res.setHeader("Content-Type", "text/event-stream; charset=utf-8");
   325→  res.setHeader("Cache-Control", "no-cache, no-transform");
   326→  res.setHeader("Connection", "keep-alive");
   327→  res.setHeader("X-Accel-Buffering", "no");
   328→  res.flushHeaders();
   329→
   330→  const send = (line: string) => {
   331→    res.write(`data: ${JSON.stringify(line)}\n\n`);
   332→    (res as unknown as { flush?: () => void }).flush?.();
   333→  };
   334→
   335→  send(`▶  ${def.cmd} ${def.args.join(" ")}`);
   336→  send("─".repeat(64));
   337→
   338→  const child = spawn(def.cmd, def.args, {
   339→    cwd: WORKSPACE_ROOT,
   340→    env: { ...process.env },
   341→    stdio: ["ignore", "pipe", "pipe"],
   342→  });
   343→
   344→  let buf = "";
   345→  const flush = (raw: string, prefix = "") => {
   346→    (buf + raw).split("\n").forEach((l, i, arr) => {
   347→      if (i < arr.length - 1) send(prefix + l);
   348→      else buf = l;
   349→    });
   350→  };
   351→
   352→  child.stdout.on("data", (chunk: Buffer) => flush(chunk.toString()));
   353→  child.stderr.on("data", (chunk: Buffer) => flush(chunk.toString(), "⚠ "));
   354→
   355→  const timer = setTimeout(() => {
   356→    send(""); send("⏱  Tiempo agotado — proceso terminado.");
   357→    child.kill("SIGTERM");
   358→  }, def.timeout);
   359→
   360→  child.on("close", (code) => {
   361→    clearTimeout(timer);
   362→    if (buf) send(buf);
   363→    send("─".repeat(64));
   364→    send(`✓  Terminado (código ${code ?? 0})`);
   365→    res.write("data: __EOF__\n\n");
   366→    res.end();
   367→  });
   368→
   369→  req.on("close", () => { clearTimeout(timer); child.kill("SIGTERM"); });
   370→});
