function isAdminEmail(email: string | null | undefined): boolean {
  if (!email) return false;
  if (email === "demo@clientum.com.ar") return false;
  return email.endsWith("@clientum.com.ar");
}

function guardAdmin(req: Request, res: Response): boolean {
  if (!req.isAuthenticated()) { res.status(401).json({ error: "No autenticado" }); return false; }
  if (!isAdminEmail(req.user.email)) { res.status(403).json({ error: "Acceso denegado" }); return false; }
  return true;
}

